  // Dynamic tooltip on "# points": recommends the best N for J2000 alignment
  // given the current Start JD and End JD.
  //
  // Formula:  ratio = (j2000JD - startJD) / (endJD - startJD)
  //   For each candidate N: step = range / (N-1)
  //                         k    = round(ratio × (N-1))   ← nearest grid step to J2000
  //                         err  = |ratio×(N-1) - k| × step   (in JD days)
  //   Best N = argmin err, searching ±2000 around target N for ~50-yr steps.
  const J2000_JD = 2451545;
  function bestNforJ2000(startJD, endJD) {
    if (!isFinite(startJD) || !isFinite(endJD) || endJD <= startJD) return null;
    const range    = endJD - startJD;
    const dist     = J2000_JD - startJD;
    const ratio    = dist / range;
    const targetN  = Math.round(range / (50 * meansolaryearlengthinDays)) + 1;
    const lo = Math.max(2, targetN - 2000);
    const hi = targetN + 2000;
    let bestN = targetN, bestErr = Infinity;
    for (let N = lo; N <= hi; N++) {
      const step   = range / (N - 1);
      const kExact = dist / step;
      const err    = Math.abs(kExact - Math.round(kExact)) * step;
      if (err < bestErr) { bestErr = err; bestN = N; }
    }
    const step    = range / (bestN - 1);
    const stepYr  = step / meansolaryearlengthinDays;
    const errDays = bestErr;
    const errYr   = errDays / meansolaryearlengthinDays;
    return { N: bestN, stepYr, errDays, errYr };
  }
  // Precompute H-factorization recommendations for the tooltip
  const _hJdStart = Math.round(startmodelJD + (balancedYear - startmodelYear) * meansolaryearlengthinDays);
  const _hJdEnd   = Math.round(_hJdStart + holisticyearLength * meansolaryearlengthinDays);
  const _hSteps = [];
  for (let d = 1; d <= holisticyearLength; d++) {
    if (holisticyearLength % d === 0 && d >= 10 && d <= 200) {
      _hSteps.push({ step: d, pts: holisticyearLength / d + 1 });
    }
  }
  // Dynamic prime factorization of H
  let _hFact = holisticyearLength, _hFactors = {};
  for (let p = 2; p * p <= _hFact; p++) {
    while (_hFact % p === 0) { _hFactors[p] = (_hFactors[p] || 0) + 1; _hFact /= p; }
  }
  if (_hFact > 1) _hFactors[_hFact] = (_hFactors[_hFact] || 0) + 1;
  const _hFactStr = Object.entries(_hFactors).map(([p, e]) => e > 1 ? p + '^' + e : p).join(' \u00D7 ');
  const _hTip =
    `\n\nFull Earth Fundamental Cycle (H = ${holisticyearLength.toLocaleString('en-US')} yr):\n` +
    `  Start JD: ${_hJdStart}  |  End JD: ${_hJdEnd}\n` +
    `  H = ${_hFactStr} — exact-divisor steps:\n` +
    _hSteps.map(s => `    ${s.step} yr → ${s.pts.toLocaleString('en-US')} pts`).join('\n');

