      console.log(`  A) current  (UT_h + dT_h):  lon = ${ssLon(jd, 'A_current').toFixed(4)}°`);
      console.log(`  B) no corr  (UT_h        ):  lon = ${ssLon(jd, 'B_no_corr').toFixed(4)}°`);
      console.log(`  C) TT→UT    (UT_h - dT_h):  lon = ${ssLon(jd, 'C_TT_correct').toFixed(4)}°`);
