          + (_rc.P || 0) * _T * _sin2U * _invD + (_rc.Q || 0) * _T * _cos2U * _invD
          + (_rc.R || 0) * _T * _sinU * _invS
          + (_rc.S || 0) * _T * _invD + (_rc.U || 0) * _cosU * _invD2
          + (_rc.V || 0) * _invS2 + (_rc.W || 0) * _sinU * _invS2
